
import React, { useState, useEffect } from 'react';
import PinView from "../../PinControls/PinView.js";
import Layout from "./Layout.js";

/**
 *  This component holds the Live Debugger UI (determined by the board chosen by the user). This component requires two data parameters (pinData, deviceData), which hold
 * the current states of the analog/digital pins (pinData) and the states of onboard sensors (deviceData). This component also accepts a serial communication method, which should be
 * (queryBoard(selection, data)), to query the board for new data or update the boards pins/sensors.
 * @param {*} param0 
 */
function DataDisplay({pinData, serialCom, deviceData}) {
    
    const [pin, selectPin] = useState({Type: 'START'});
    
    useEffect(
        () => {
            if(pin)
            {
                serialCom("PINS");
            }
        },
        [pin.Type]//For sensors that require delays/refreshed data we need to set a TimeInterval for continously querying the sensor data
    );

    /*****************************************************************************
     * This function will reset the styling of the previous pin, set the current pin, and update the current pin's styling to show it has been selected.
     * *********************************************************************/
    function updatePin(data)
    {
        if(pin.Type !== 'START')
        {
            /* Update Previous Selection */
            const rectElement = document.getElementById(pin.Digital + "_rect");
            rectElement.setAttribute("fill", "white");
            const textElement = document.getElementById(pin.Digital + "_text");
            textElement.setAttribute("fill", "black");
            if(pin.hasOwnProperty("Class"))
            {
                let svgElements = document.querySelectorAll(pin.Class);
                svgElements.forEach(element =>{
                        element.setAttribute("fill", "white");
                        element.setAttribute("font-size", 3.341)
                        if(pin.Class.indexOf("D") != -1)
                        {//Digital pins need to be shifted back to their original position
                            let transform = String(element.getAttribute("transform"));
                            element.setAttribute("transform", transform.substring(0, transform.indexOf("translate")));
                        }
                    }
                );   
            }
        }
        const rectElement = document.getElementById(data.Digital + "_rect");
        rectElement.setAttribute("fill", "black");
        const textElement = document.getElementById(data.Digital + "_text");
        textElement.setAttribute("fill", "white");

        if(data.hasOwnProperty("Class"))
        {
            let svgElements = document.querySelectorAll(data.Class);
            svgElements.forEach(element =>{
                    element.setAttribute("fill", "yellow");
                    element.setAttribute("font-size", 6);
                    if(data.Class.indexOf("D") != -1)
                    {//Digital pins need to be shifted left, so they aren't hidden by the hardware pin connectors.
                        let transform = element.getAttribute("transform");
                        element.setAttribute("transform", transform + "translate(-" + String(element.textContent.length + 1) + ", 1)");
                        
                    }
                }
            ); 
        }
        selectPin(data);
    } /* End updatePin(data); */

    let data = {
                    Type: "START",
                    Analog: "NA",//Verify the pin is present
                    Analog_Id: "START",
                    Digital: "NA",//Verify the pin is present
                    Digital_Id: "START",
                    Pwm:  0,
                    Pwm_Id: "START"
                };  
    let disabled = false;
    if(pin)
    {
        if(pinData !== null)
        {//May need to also check if deviceData has been set
            try{
                data = {
                    Type: "PINS",
                    Analog: pin.Analog in pinData ? pinData[pin.Analog] : "NA",//Verify the pin is present
                    Analog_Id: pin.Analog,
                    Digital: pin.Digital in pinData ? pinData[pin.Digital] : "NA",//Verify the pin is present
                    Digital_Id: pin.Digital,
                    Pwm: pin.Pwm in deviceData.pwm ? deviceData.pwm[pin.Pwm] : 0,
                    Pwm_Id: pin.Pwm
                };

            }
            catch(e){
                console.log("Pin [" + pin + "] has no Data!");
            }
        }
        
    }

  return (
      <>    
        <svg 
            width={"100%"} 
            viewBox="0 0 1440 1024"
        >
            <PinView data={data} update={serialCom} /> 
            <Layout pinData={pinData} data={data} deviceData={deviceData} disabled={disabled} trigger={updatePin}/>;
        </svg>
     </>

    );
}

export default DataDisplay