import * as React from "react"
import PinSelector from "../../PinControls/PinSelector.js"
import Board from "./Board.js"
import PinKey from "../../PinControls/PinKey.js"

function Layout({pinData, trigger, disabled, deviceData}) {
      return (
          <>
            <Board width={550} height={550} x={420.08} y={125} />
            {/* Animations for the pin's current state (Low, High, High-In, PWM-ON, Disabled*/}
            <defs>  
                <linearGradient id="pinGradientHigh" x1="0%" y1="0%" x2="100%" y2="100%" > 
                    <stop offset="0%" stopColor="red">
                        <animate attributeName="stop-color" values="white;red;white" dur="1.5s" repeatCount="indefinite"></animate>
                    </stop>
                </linearGradient>
                <linearGradient id="pinGradientHighIn" x1="0%" y1="0%" x2="100%" y2="100%" > 
                    <stop offset="0%" stopColor="yellow">
                        <animate attributeName="stop-color" values="white;yellow;white" dur="1.5s" repeatCount="indefinite"></animate>
                    </stop>
                </linearGradient>
                <linearGradient id="pinGradientPwmOn" x1="0%" y1="0%" x2="100%" y2="100%" > 
                    <stop offset="0%" stopColor="#66CCEE">
                        <animate attributeName="stop-color" values="white;#66CCEE;white" dur="1.5s" repeatCount="indefinite"></animate>
                    </stop>
                </linearGradient>
                <linearGradient id="pinDisabled" x1="0%" y1="0%" x2="100%" y2="100%" > 
                    <stop offset="0%" stopColor="black">
                        <animate attributeName="stop-color" values="black" dur="1.5s" repeatCount="indefinite"></animate>
                    </stop>
                </linearGradient>
              </defs>
            
              
            {/*Analog Pins */}
            <PinSelector analog="A5" digital="D19" pwm="NA" x={437} y={628.598} trigger={trigger} width={70} height={16.166} setting={disabled ? 4 : pinData !== null ? pinData.hasOwnProperty("D19") ? pinData["D19"][0] : 0 : 0} place_text_to_right={false} id="A5" class_name=".A5_Text"/>
            <PinSelector analog="A4" digital="D18" pwm="NA" x={437} y={610.032} trigger={trigger} width={70} height={16.166} setting={disabled ? 4 : pinData !== null ? pinData.hasOwnProperty("D18") ? pinData["D18"][0] : 0 : 0} place_text_to_right={false} id="A4" class_name=".A4_Text"/>
            <PinSelector analog="A3" digital="D17" pwm="NA" x={437} y={591.466} trigger={trigger} width={70} height={16.166} setting={disabled ? 4 : pinData !== null ? pinData.hasOwnProperty("D17") ? pinData["D17"][0] : 0 : 0} place_text_to_right={false} id="A3" class_name=".A3_Text"/>
            <PinSelector analog="A2" digital="D16" pwm="NA" x={437} y={572.9}   trigger={trigger} width={70} height={16.166} setting={disabled ? 4 : pinData !== null ? pinData.hasOwnProperty("D16") ? pinData["D16"][0] : 0 : 0} place_text_to_right={false} id="A2" class_name=".A2_Text"/>
            <PinSelector analog="A1" digital="D15" pwm="NA" x={437} y={554.316} trigger={trigger} width={70} height={16.166} setting={disabled ? 4 : pinData !== null ? pinData.hasOwnProperty("D15") ? pinData["D15"][0] : 0 : 0} place_text_to_right={false} id="A1" class_name=".A1_Text"/>
            <PinSelector analog="A0" digital="D14" pwm="NA" x={437} y={535.75}  trigger={trigger} width={70} height={16.166} setting={disabled ? 4 : pinData !== null ? pinData.hasOwnProperty("D14") ? pinData["D14"][0] : 0 : 0} place_text_to_right={false} id="A0" class_name=".A0_Text"/>
           
            {/*Digital Pins */}
            <PinSelector analog="NA" digital="D2" pwm="NA" x={880} y={591.33}  trigger={trigger} width={70} height={16.166} setting={disabled ? 4 : pinData !== null ? pinData.hasOwnProperty("D2") ? pinData["D2"][0] : 0 : 0} id="2" class_name=".D2_Text"/>
            <PinSelector analog="NA" digital="D3" pwm="D3" x={880} y={572.764} trigger={trigger} width={70} height={16.166} setting={disabled ? 4 : deviceData.pwm["D3"] > 0 && deviceData.pwm["D3"] < 255 ? 3 :pinData !== null ? pinData.hasOwnProperty("D3") ? pinData["D3"][0] : 0 : 0} id="3" class_name=".D3_Text"/>
            <PinSelector analog="NA" digital="D4" pwm="NA" x={880} y={554.198} trigger={trigger} width={70} height={16.166} setting={disabled ? 4 : pinData !== null ? pinData.hasOwnProperty("D4") ? pinData["D4"][0] : 0 : 0} id="4" class_name=".D4_Text"/>
            <PinSelector analog="NA" digital="D5" pwm="D5" x={880} y={535.632} trigger={trigger} width={70} height={16.166} setting={disabled ? 4 : deviceData.pwm["D5"] > 0 && deviceData.pwm["D5"] < 255 ? 3 : pinData !== null ? pinData.hasOwnProperty("D5") ? pinData["D5"][0] : 0 : 0} id="5" class_name=".D5_Text"/>
            <PinSelector analog="NA" digital="D6" pwm="D6" x={880} y={517.066} trigger={trigger} width={70} height={16.166} setting={disabled ? 4 : deviceData.pwm["D6"] > 0 && deviceData.pwm["D6"] < 255 ? 3 : pinData !== null ? pinData.hasOwnProperty("D6") ? pinData["D6"][0] : 0 : 0} id="6" class_name=".D6_Text"/>
            <PinSelector analog="NA" digital="D7" pwm="NA" x={880} y={498.5}   trigger={trigger} width={70} height={16.166} setting={disabled ? 4 : pinData !== null ? pinData.hasOwnProperty("D7") ? pinData["D7"][0] : 0 : 0} id="7" class_name=".D7_Text"/>

            <PinSelector analog="NA" digital="D8" pwm="NA"   x={880} y={468.75}  trigger={trigger} width={70} height={16.166} setting={disabled ? 4 : pinData !== null ? pinData.hasOwnProperty("D8") ? pinData["D8"][0] : 0 : 0}   id="8"  class_name=".D8_Text"/>
            <PinSelector analog="NA" digital="D9" pwm="D9"   x={880} y={450.184} trigger={trigger} width={70} height={16.166} setting={disabled ? 4 : deviceData.pwm["D9"] > 0 && deviceData.pwm["D9"] < 255 ? 3  : pinData !== null ? pinData.hasOwnProperty("D9") ? pinData["D9"][0] : 0 : 0}   id="9"  class_name=".D9_Text"/>
            <PinSelector analog="NA" digital="D10" pwm="D10" x={880} y={431.618} trigger={trigger} width={70} height={16.166} setting={disabled ? 4 : deviceData.pwm["D10"] > 0 && deviceData.pwm["D10"] < 255 ? 3 : pinData !== null ? pinData.hasOwnProperty("D10") ? pinData["D10"][0] : 0 : 0} id="10" class_name=".D10_Text"/>
            <PinSelector analog="NA" digital="D11" pwm="D11" x={880} y={413.052} trigger={trigger} width={70} height={16.166} setting={disabled ? 4 : deviceData.pwm["D11"] > 0 && deviceData.pwm["D11"] < 255 ? 3 :pinData !== null ? pinData.hasOwnProperty("D11") ? pinData["D11"][0] : 0 : 0} id="11" class_name=".D11_Text"/>
            <PinSelector analog="NA" digital="D12" pwm="NA"  x={880} y={394.486} trigger={trigger} width={70} height={16.166} setting={disabled ? 4 : pinData !== null ? pinData.hasOwnProperty("D12") ? pinData["D12"][0] : 0 : 0} id="12" class_name=".D12_Text"/>
            <PinSelector analog="NA" digital="D13" pwm="NA"  x={880} y={375.92}  trigger={trigger} width={70} height={16.166} setting={disabled ? 4 : pinData !== null ? pinData.hasOwnProperty("D13") ? pinData["D13"][0] : 0 : 0} id="13" class_name=".D13_Text"/>
            <PinKey x={0} y={116} /> 
         </>
    
    )
}

export default Layout;